/**
 * Theme definitions for T3 Code.
 *
 * Each theme is pure data — no DOM or React dependencies — so this module
 * can be imported from any environment (server, web, desktop).
 */

export interface ThemeColors {
  /** Main canvas background. */
  background: string;
  /** Default body text color. */
  foreground: string;
  /** Subtle interactive / hover surface. */
  accent: string;
  /** Sidebar panel background. */
  sidebar: string;
  /** Code-editor pane background. */
  editor: string;
  /** Terminal pane background. */
  terminal: string;
  /** Bottom status-bar background. */
  statusBar: string;
}

export interface Theme {
  /** Unique identifier, e.g. "t3-dark". */
  id: string;
  /** Human-readable display name. */
  name: string;
  /**
   * Whether this theme is a dark or light palette.
   * Controls the Tailwind `.dark` class on `<html>`.
   */
  colorScheme: "light" | "dark";
  colors: ThemeColors;
  /** Optional font-family override (CSS value). */
  fontFamily?: string;
  /** Optional base font-size override (CSS value, e.g. "14px"). */
  fontSize?: string;
}

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    colors: {
      // Matches existing dark-mode CSS vars in index.css exactly.
      background: "color-mix(in srgb, oklch(0.145 0 0) 95%, white)",
      foreground: "oklch(0.95 0 0)",
      accent: "oklch(0.23 0 0)",
      sidebar: "oklch(0.13 0 0)",
      editor: "oklch(0.155 0 0)",
      terminal: "oklch(0.12 0 0)",
      statusBar: "oklch(0.10 0 0)",
    },
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colorScheme: "light",
    colors: {
      // Matches existing light-mode CSS vars in index.css exactly.
      background: "oklch(1 0 0)",
      foreground: "oklch(0.374 0 0)",
      accent: "oklch(0.96 0 0)",
      sidebar: "oklch(0.97 0 0)",
      editor: "oklch(1 0 0)",
      terminal: "oklch(0.98 0 0)",
      statusBar: "oklch(0.94 0 0)",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colorScheme: "dark",
    colors: {
      // Deep blue-purple palette.
      background: "oklch(0.10 0.025 264)",
      foreground: "oklch(0.93 0.015 264)",
      accent: "oklch(0.18 0.04 264)",
      sidebar: "oklch(0.09 0.025 264)",
      editor: "oklch(0.12 0.025 264)",
      terminal: "oklch(0.08 0.02 264)",
      statusBar: "oklch(0.07 0.025 264)",
    },
  },
] satisfies readonly Theme[];

/**
 * Return all built-in themes in display order.
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Look up a theme by its `id`.
 * Returns `undefined` when no match is found.
 */
export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

