import { useCallback, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme-id:v1";
const DEFAULT_THEME_ID = "t3-dark";

let listeners: Array<() => void> = [];
let lastTheme: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  try {
    return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
  } catch {
    return DEFAULT_THEME_ID;
  }
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

function applyTheme(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle dark / light class for Tailwind's `dark:` variant.
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");

  // Set the seven semantic color tokens as inline CSS custom properties.
  // Inline styles take precedence over stylesheet rules, so these override
  // the default light/dark values declared in index.css.
  const { colors } = theme;
  const el = document.documentElement;
  el.style.setProperty("--background", colors.background);
  // Keep card / popover surfaces in sync with the main canvas.
  el.style.setProperty("--card", colors.background);
  el.style.setProperty("--popover", colors.background);

  el.style.setProperty("--foreground", colors.foreground);
  el.style.setProperty("--card-foreground", colors.foreground);
  el.style.setProperty("--popover-foreground", colors.foreground);

  el.style.setProperty("--accent", colors.accent);
  el.style.setProperty("--accent-foreground", colors.foreground);

  // New semantic vars consumed by layout components.
  el.style.setProperty("--sidebar-background", colors.sidebar);
  el.style.setProperty("--editor-background", colors.editor);
  el.style.setProperty("--terminal-background", colors.terminal);
  el.style.setProperty("--status-bar-background", colors.statusBar);

  if (theme.fontFamily) {
    el.style.setProperty("--font-family", theme.fontFamily);
  }
  if (theme.fontSize) {
    el.style.setProperty("--font-size-base", theme.fontSize);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent a flash of unstyled content.
applyTheme(resolveTheme(getStoredId()));

function getSnapshot(): Theme {
  const theme = resolveTheme(getStoredId());
  // Stable reference: return the same object as long as id hasn't changed.
  if (lastTheme && lastTheme.id === theme.id) {
    return lastTheme;
  }
  lastTheme = theme;
  return lastTheme;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync changes made from other tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveTheme(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
