import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/**
 * A grid of theme cards with color-swatch previews.
 * Self-contained — reads and writes the current theme via `useTheme()`.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="grid grid-cols-1 gap-2 sm:grid-cols-3">
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(t.id)}
            className={cn(
              "flex flex-col gap-3 rounded-xl border px-3 py-3 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
          >
            {/* Color swatches */}
            <div className="flex items-center gap-1.5">
              <ColorSwatch color={t.colors.background} label="Background" border />
              <ColorSwatch color={t.colors.sidebar} label="Sidebar" border />
              <ColorSwatch color={t.colors.accent} label="Accent" border />
              <ColorSwatch color={t.colors.foreground} label="Foreground" />
            </div>

            {/* Theme name + selected badge */}
            <div className="flex items-center justify-between gap-2">
              <span className="text-sm font-medium leading-none">{t.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

interface ColorSwatchProps {
  color: string;
  label: string;
  /** Add a subtle border so very-light swatches are visible on light backgrounds. */
  border?: boolean;
}

function ColorSwatch({ color, label, border = false }: ColorSwatchProps) {
  return (
    <span
      aria-label={label}
      className={cn(
        "block size-4 rounded-full",
        border && "ring-1 ring-inset ring-black/10",
      )}
      style={{ background: color }}
    />
  );
}

